function elo(data) {
  // Sort the players by their Matches property.
  data.sort((a, b) => a.Matches - b.Matches);

  // Select the first player as the lowest result.
  let Player1 = data[0];

  // Select the second player randomly.
  let Player2 = data[Math.floor(Math.random() * data.length)];

  // Return the selected players.
  return { Player1, Player2 };
}
