To ensure that the memory region is mapped, you can use the `vmalloc` function provided by the Linux kernel. This function allocates memory from the kernel's virtual memory area (VMA).

Here's an example of how to use `vmalloc` to allocate memory at the desired virtual address:

```c
#include <linux/module.h>
#include <linux/slab.h>
#include <linux/vmalloc.h>

#define MEM_SIZE 4096

static void *mem;

static int __init my_module_init(void)
{
    mem = vmalloc(MEM_SIZE);
    if (mem == NULL) {
        pr_err("Failed to allocate memory\n");
        return -ENOMEM;
    }
    pr_info("Memory allocated at %p\n", mem);
    return 0;
}

static void __exit my_module_exit(void)
{
    vfree(mem);
    pr_info("Memory freed\n");
}

module_init(my_module_init);
module_exit(my_module_exit);
```

In this example, the `vmalloc` function is used to allocate memory at the desired virtual address. The allocated memory is then freed using the `vfree` function.

