    this.outputLayer = new Array(outputSize).fill(0);

    for (let I = 0; I < this.weights.length; i++) {
      this.weights[i] = new Array(this.hiddenLayer.length).fill(0);
    }
  }

  public feedForward(input: number[]): number[] {
    for (let I = 0; I < this.hiddenLayer.length; i++) {
      this.hiddenLayer[i] = 0;
    }

    for (let I = 0; I < this.hiddenLayer.length; i++) {
      for (let j = 0; j < this.hiddenLayer.length; j++) {
        this.hiddenLayer[i] += input[j] * this.weights[i][j];
      }
    }

    for (let I = 0; I < this.outputLayer.length; i++) {
      this.outputLayer[i] = 0;
    }

    for (let I = 0; I < this.outputLayer.length; i++) {
      for (let j = 0; j < this.outputLayer.length; j++) {
        this.outputLayer[i] += this.hiddenLayer[j] * this.weights[i][j];
      }
    }

    return this.outputLayer;
  }

  public backPropagation(input: number[], expectedOutput: number[]): number[] {
    const output = this.feedForward(input);

    const error = this.calculateError(expectedOutput, output);

    this.updateWeights(input, output, error);

    return error;
  }

  private calculateError(expectedOutput: number[], output: number[]): number[] {
    const error = [];

    for (let I = 0; I < expectedOutput.length; i++) {
      error[i] = expectedOutput[i] - output[i];
    }

    return error;
  }

  private updateWeights(input: number[], output: number[], error: number[]): void {
    for (let I = 0; I < this.weights.length; i++) {
      for (let j = 0; j < this.weights[i].length; j++) {
        this.weights[i][j] += this.learningRate * error[i] * input[j];
      }
    }
  }
}

