```javascript
function searchEntityValue(json, entityKey) {
  // Check if the input is a JSON object
  if (typeof json !== 'object') {
    throw new Error('Input must be a JSON object');
  }

  // Check if the entity key is a string
  if (typeof entityKey !== 'string') {
    throw new Error('Entity key must be a string');
  }

  // Recursively search for the entity key in the JSON object
  function searchEntityValueHelper(obj, entityKey, path) {
    // Check if the object is a JSON array
    if (Array.isArray(obj)) {
      // Loop through the array and search for the entity key
      for (let I = 0; I < obj.length; i++) {
        // Recursively search for the entity key in the current array element
        searchEntityValueHelper(obj[i], entityKey, path + (i > 0 ? '.' : '') + I));
      }
    } else {
      // Check if the object is a JSON object
      if (typeof obj === 'object') {
        // Recursively search for the entity key in the current JSON object
        searchEntityValueHelper(obj, entityKey, path);
      }
    }
  }

  // Call the recursive function to search for the entity key
  try {
    searchEntityValueHelper(json, entityKey, '');
  } catch (err) {
    console.error(err);
  }

  // Return the value of the entity key and the path to the entity key
  return {
    value: json[entityKey],
    path: path + entityKey
  };
}
```

